import { ORDINAL_DATATYPE } from '../../datatype-constants';
import { arrayFind, defined, isUndefined } from '../../../utils/zcutils';
import { convertNull } from './convert-null';

export function getSizeFromPoint(d, dataSet, chartObj) {
    let val = dataSet.getZ(d),
        scaleComponent = arrayFind(chartObj.scales, _ => _.id === 'z-0'),
        { scale, config, schema } = scaleComponent,
        { dataType } = schema.data,
        { nullAs } = config;

    if (isUndefined(val)) {
        if (defined(nullAs)) {
            let nullAsOptions = { config, scale, columnKey: chartObj.dataset.getColumnIdx('z') };
            return scale(convertNull(val, nullAsOptions));
        } else if (dataType === ORDINAL_DATATYPE) {
            return scale(val);
        } else {
            return scale(scale.domain()[0]);
        }
    }

    return scale(val);
}
